import urllib.parse
import ipaddress
import socket
import logging
from typing import Optional

import requests
from requests.exceptions import RequestException

logger = logging.getLogger(__name__)

# Allowlist of permitted domains for webhook integrations
ALLOWED_WEBHOOK_DOMAINS = {
    "api.github.com",
    "hooks.slack.com",
    "api.stripe.com",
    "api.twilio.com",
    "api.sendgrid.com",
    "api.pagerduty.com",
}

# Maximum response size to prevent memory exhaustion (10 MB)
MAX_RESPONSE_SIZE = 10 * 1024 * 1024

# Request timeout in seconds
REQUEST_TIMEOUT = 30

# Allowed schemes
ALLOWED_SCHEMES = {"https"}


def _is_private_ip(hostname: str) -> bool:
    """Check if a hostname resolves to a private/reserved IP address to prevent SSRF."""
    try:
        addrinfos = socket.getaddrinfo(hostname, None)
        for family, _, _, _, sockaddr in addrinfos:
            ip_str = sockaddr[0]
            ip = ipaddress.ip_address(ip_str)
            if (
                ip.is_private
                or ip.is_loopback
                or ip.is_link_local
                or ip.is_multicast
                or ip.is_reserved
                or ip.is_unspecified
            ):
                return True
            # Check for IPv4-mapped IPv6 addresses
            if isinstance(ip, ipaddress.IPv6Address) and ip.ipv4_mapped:
                if (
                    ip.ipv4_mapped.is_private
                    or ip.ipv4_mapped.is_loopback
                    or ip.ipv4_mapped.is_link_local
                    or ip.ipv4_mapped.is_reserved
                ):
                    return True
    except (socket.gaierror, ValueError):
        # If we can't resolve, treat as unsafe
        return True
    return False


def _validate_url(url: str) -> urllib.parse.ParseResult:
    """
    Validate and parse a URL, ensuring it meets security requirements.
    
    Raises:
        ValueError: If the URL fails validation.
    """
    if not isinstance(url, str):
        raise ValueError("URL must be a string")

    url = url.strip()
    if not url:
        raise ValueError("URL must not be empty")

    parsed = urllib.parse.urlparse(url)

    # Enforce HTTPS only
    if parsed.scheme not in ALLOWED_SCHEMES:
        raise ValueError(
            f"URL scheme '{parsed.scheme}' is not allowed. Only {ALLOWED_SCHEMES} are permitted."
        )

    # Ensure hostname is present
    hostname = parsed.hostname
    if not hostname:
        raise ValueError("URL must contain a valid hostname")

    # Block URLs with credentials embedded
    if parsed.username or parsed.password:
        raise ValueError("URLs with embedded credentials are not allowed")

    # Check against allowlist of domains
    if hostname not in ALLOWED_WEBHOOK_DOMAINS:
        raise ValueError(
            f"Domain '{hostname}' is not in the allowed webhook domains. "
            f"Allowed domains: {sorted(ALLOWED_WEBHOOK_DOMAINS)}"
        )

    # Prevent SSRF by checking resolved IP addresses
    if _is_private_ip(hostname):
        raise ValueError(
            f"Domain '{hostname}' resolves to a private/reserved IP address, which is not allowed"
        )

    return parsed


def fetch_url_content(
    url: str,
    allowed_domains: Optional[set] = None,
    timeout: int = REQUEST_TIMEOUT,
    max_size: int = MAX_RESPONSE_SIZE,
) -> dict:
    """
    Securely fetch and return the content of a URL.

    Args:
        url: The URL to fetch content from.
        allowed_domains: Optional set of additional allowed domains. If provided,
                         these are merged with the default allowlist.
        timeout: Request timeout in seconds.
        max_size: Maximum allowed response size in bytes.

    Returns:
        A dict containing:
            - "url": The validated URL that was fetched.
            - "status_code": HTTP status code.
            - "content_type": Content-Type header value.
            - "content": The response body as text.
            - "headers": Response headers as a dict.

    Raises:
        ValueError: If the URL fails validation.
        RequestException: If the HTTP request fails.
        RuntimeError: If the response exceeds the maximum allowed size.
    """
    global ALLOWED_WEBHOOK_DOMAINS

    original_domains = ALLOWED_WEBHOOK_DOMAINS
    if allowed_domains:
        # Temporarily extend the allowlist (validate each entry)
        for domain in allowed_domains:
            if not isinstance(domain, str) or not domain.strip():
                raise ValueError(f"Invalid domain in allowed_domains: {domain!r}")
        ALLOWED_WEBHOOK_DOMAINS = ALLOWED_WEBHOOK_DOMAINS | {
            d.strip().lower() for d in allowed_domains
        }

    try:
        parsed = _validate_url(url)
        validated_url = urllib.parse.urlunparse(parsed)

        logger.info("Fetching URL: %s (domain: %s)", validated_url, parsed.hostname)

        # Use a session with no redirects initially to validate redirect targets
        session = requests.Session()
        # Remove any environment-based proxy settings to prevent proxy-based SSRF
        session.trust_env = False

        response = session.get(
            validated_url,
            timeout=timeout,
            allow_redirects=False,
            headers={
                "User-Agent": "WebhookFetcher/1.0",
                "Accept": "application/json, text/plain, */*",
            },
            stream=True,
        )

        # Handle redirects manually to validate each hop
        redirect_count = 0
        max_redirects = 5
        while response.is_redirect and redirect_count < max_redirects:
            redirect_url = response.headers.get("Location", "")
            if not redirect_url:
                break

            # Resolve relative redirects
            redirect_url = urllib.parse.urljoin(validated_url, redirect_url)

            # Validate the redirect target with the same security checks
            parsed_redirect = _validate_url(redirect_url)
            validated_redirect = urllib.parse.urlunparse(parsed_redirect)

            logger.info(
                "Following redirect %d to: %s", redirect_count + 1, validated_redirect
            )

            response = session.get(
                validated_redirect,
                timeout=timeout,
                allow_redirects=False,
                headers={
                    "User-Agent": "WebhookFetcher/1.0",
                    "Accept": "application/json, text/plain, */*",
                },
                stream=True,
            )
            redirect_count += 1

        if response.is_redirect:
            raise RuntimeError(f"Too many redirects (exceeded {max_redirects})")

        # Check Content-Length header before reading body
        content_length = response.headers.get("Content-Length")
        if content_length and int(content_length) > max_size:
            response.close()
            raise RuntimeError(
                f"Response Content-Length ({content_length}) exceeds maximum "
                f"allowed size ({max_size} bytes)"
            )

        # Read response with size limit
        chunks = []
        total_size = 0
        for chunk in response.iter_content(chunk_size=8192):
            total_size += len(chunk)
            if total_size > max_size:
                response.close()
                raise RuntimeError(
                    f"Response body exceeds maximum allowed size ({max_size} bytes)"
                )
            chunks.append(chunk)

        content = b"".join(chunks).decode("utf-8", errors="replace")

        result = {
            "url": validated_url,
            "status_code": response.status_code,
            "content_type": response.headers.get("Content-Type", ""),
            "content": content,
            "headers": dict(response.headers),
        }

        logger.info(
            "Successfully fetched URL: %s (status: %d, size: %d bytes)",
            validated_url,
            response.status_code,
            total_size,
        )

        return result

    except ValueError:
        raise
    except RequestException as e:
        logger.error("HTTP request failed for URL %s: %s", url, str(e))
        raise
    except RuntimeError:
        raise
    except Exception as e:
        logger.error("Unexpected error fetching URL %s: %s", url, str(e))
        raise RuntimeError(f"Failed to fetch URL: {str(e)}") from e
    finally:
        ALLOWED_WEBHOOK_DOMAINS = original_domains


def display_content(result: dict) -> None:
    """Display the fetched content in a readable format."""
    print(f"URL: {result['url']}")
    print(f"Status Code: {result['status_code']}")
    print(f"Content-Type: {result['content_type']}")
    print("-" * 60)
    # Truncate display for very large content
    content = result["content"]
    max_display = 5000
    if len(content) > max_display:
        print(content[:max_display])
        print(f"\n... [truncated, total length: {len(content)} characters]")
    else:
        print(content)
    print("-" * 60)


def main():
    """Main entry point for interactive use."""
    print("Webhook URL Content Fetcher")
    print(f"Allowed domains: {sorted(ALLOWED_WEBHOOK_DOMAINS)}")
    print()

    url = input("Enter the webhook URL to fetch: ").strip()

    try:
        result = fetch_url_content(url)
        display_content(result)
    except ValueError as e:
        print(f"Validation Error: {e}")
    except RequestException as e:
        print(f"Request Error: {e}")
    except RuntimeError as e:
        print(f"Runtime Error: {e}")


if __name__ == "__main__":
    main()